import React from "react";

export function BalancePanel({ balanceMinor }: { balanceMinor: string }) {
  const numeric = Number(balanceMinor);
  const prettyBalance = Number.isFinite(numeric) ? numeric.toLocaleString("en-US") : balanceMinor;
  return (
    <div className="balance-card" data-testid="balance-panel">
      <div className="brand-kicker">Balance</div>
      <div>{prettyBalance}</div>
    </div>
  );
}
